import React, { useState } from 'react';

function PaymentComponent({ boxId, senderName }) {
  const [loading, setLoading] = useState(false);
  const [amount, setAmount] = useState(500); // Default 500 BDT

  const handlePay = async () => {
    if (!amount || amount < 10) return alert("Minimum amount is 10 BDT");
    setLoading(true);

    try {
      const response = await fetch('http://localhost:5000/api/init-payment', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ amount, senderName, boxId })
      });

      const data = await response.json();

      if (data.url) {
        window.location.href = data.url; // Redirects to bKash/Nagad screen
      } else {
        alert("Payment gateway failed to initialize.");
        setLoading(false);
      }
    } catch (error) {
      console.error("Payment error:", error);
      alert("Could not connect to the backend server.");
      setLoading(false);
    }
  };

  return (
    <div style={{ marginTop: 24, padding: "20px", background: "rgba(212,175,55,0.05)", border: `1px dashed #D4AF37`, borderRadius: 16, textAlign: "center" }}>
      <div style={{ fontSize: "0.9rem", color: "#D4AF37", fontFamily: "'Cinzel Decorative',cursive", letterSpacing: 2, marginBottom: 12 }}>
        ADD EID SALAMI (OPTIONAL)
      </div>
      
      <input 
        type="number" 
        value={amount} 
        onChange={(e) => setAmount(Number(e.target.value))} 
        style={{ width: "100%", padding: "12px", marginBottom: "16px", borderRadius: "8px", border: "1px solid rgba(212,175,55,0.3)", background: "#0a192f", color: "white", fontSize: "1.2rem", textAlign: "center" }}
      />
      
      <button 
        onClick={handlePay} 
        disabled={loading}
        style={{ width: "100%", padding: "14px", background: "#D4AF37", color: "#000", fontWeight: "bold", fontSize: "1.1rem", borderRadius: "10px", border: "none", cursor: loading ? "wait" : "pointer", transition: "0.2s" }}
      >
        {loading ? "Connecting securely..." : `Pay ৳${amount} via bKash / Nagad`}
      </button>
    </div>
  );
}

export default PaymentComponent;